    int count = 0;
    while(left<right){
        if(s[left]!=s[right]){
            if(s[left]==s[right-1]){
                count++;
                right--;
            }
            else if(s[left+1]==s[right]){
                count++;
                left++;
            }
            else return false;
        }
        else{
            left++;
            right--;
        }
    }
