#include <stdio.h>
#include <stdbool.h>
#include <string.h>

// Helper function to check if a substring is a palindrome
bool isPalindrome(const char* s, int left, int right) {
    while (left < right) {
        if (s[left] != s[right]) {
            return false;
        }
        left++;
        right--;
    }
    return true;
}

// Function to check if the string can be a palindrome after deleting at most one character
bool validPalindrome(const char* s) {
    int left = 0;
    int right = strlen(s) - 1;

    while (left < right) {
        if (s[left] != s[right]) {
            // Check by skipping either left character or right character
            return isPalindrome(s, left + 1, right) || isPalindrome(s, left, right - 1);
        }
        left++;
        right--;
    }
    return true;
}

int main() {
    int n;
    scanf("%d", &n);
    char s[100000];
